<script setup lang="ts">
const ICON_OPTIONS = [
  { value: 'youtube', label: 'YouTube' },
  { value: 'vk', label: 'ВКонтакте' },
  { value: 'ok', label: 'Одноклассники' },
  { value: 'telegram', label: 'Telegram' },
  { value: 'rutube', label: 'RuTube' },
  { value: 'dzen', label: 'Дзен' },
  { value: 'whatsapp', label: 'WhatsApp' },
  { value: 'link', label: 'Общая ссылка' },
];

interface SocialLink {
  label: string;
  href: string;
  icon: string;
}

const { user, isAuthenticated } = useAuth();
const { getSocialLinks, updateSocialLinks } = useApi();

const title = ref('');
const links = ref<SocialLink[]>([]);
const loading = ref(false);
const saving = ref(false);
const error = ref('');
const message = ref('');

async function fetchLinks() {
  loading.value = true;
  error.value = '';
  try {
    const res: any = await getSocialLinks();
    title.value = res?.title || '';
    links.value = Array.isArray(res?.links) ? res.links.map((l: any) => ({ label: l.label || '', href: l.href || '', icon: l.icon || 'link' })) : [];
  } catch (err: any) {
    error.value = err?.data?.message || err?.message || 'Ошибка загрузки соцсетей';
  } finally {
    loading.value = false;
  }
}

function addLink() {
  links.value.push({ label: '', href: '', icon: 'link' });
}

function removeLink(index: number) {
  links.value.splice(index, 1);
}

async function save() {
  saving.value = true;
  error.value = '';
  message.value = '';
  try {
    const payload = {
      title: title.value.trim(),
      links: links.value
        .map((l) => ({ label: l.label.trim(), href: l.href.trim(), icon: l.icon || 'link' }))
        .filter((l) => l.label && l.href),
    };
    await updateSocialLinks(payload);
    message.value = 'Соцсети сохранены';
    await fetchLinks();
  } catch (err: any) {
    error.value = err?.data?.message || err?.message || 'Ошибка сохранения соцсетей';
  } finally {
    saving.value = false;
  }
}

onMounted(() => {
  if (!isAuthenticated.value || user.value?.role !== 'admin') {
    navigateTo('/account');
    return;
  }
  fetchLinks();
});
</script>

<template>
  <div class="mx-auto max-w-6xl px-4 py-8">
    <div class="mb-6 border-b border-foreground/10 pb-4">
      <p class="text-xs font-medium uppercase tracking-wider text-foreground/50">Администрирование</p>
      <h1 class="mt-2 font-heading text-2xl font-bold">Социальные сети</h1>
    </div>

    <NuxtLink to="/account" class="text-sm text-accent hover:underline">← Назад в кабинет</NuxtLink>

    <AdminTabs class="mt-6" />

    <p v-if="loading" class="mt-6 text-sm text-foreground/60">Загрузка...</p>
    <p v-if="error" class="mt-6 text-sm text-red-600">{{ error }}</p>
    <p v-if="message" class="mt-6 text-sm text-green-600">{{ message }}</p>

    <div v-if="!loading" class="mt-6 space-y-6">
      <div>
        <label class="mb-1 block text-xs font-medium text-foreground/70">Заголовок блока</label>
        <input v-model="title" type="text" class="w-full max-w-md border border-foreground/10 bg-card px-3 py-2 text-sm outline-none focus:border-accent" placeholder="Например, Мы в соцсетях">
      </div>

      <div class="space-y-4">
        <div v-for="(link, index) in links" :key="index" class="flex flex-col gap-3 rounded border border-foreground/10 bg-foreground/5 p-4 md:flex-row md:items-end">
          <div class="flex-1">
            <label class="mb-1 block text-xs font-medium text-foreground/70">Название</label>
            <input v-model="link.label" type="text" class="w-full border border-foreground/10 bg-card px-3 py-2 text-sm outline-none focus:border-accent" placeholder="YouTube">
          </div>
          <div class="flex-[2]">
            <label class="mb-1 block text-xs font-medium text-foreground/70">Ссылка</label>
            <input v-model="link.href" type="url" class="w-full border border-foreground/10 bg-card px-3 py-2 text-sm outline-none focus:border-accent" placeholder="https://youtube.com/@channel">
          </div>
          <div class="w-full md:w-48">
            <label class="mb-1 block text-xs font-medium text-foreground/70">Иконка</label>
            <select v-model="link.icon" class="w-full border border-foreground/10 bg-card px-3 py-2 text-sm outline-none focus:border-accent">
              <option v-for="opt in ICON_OPTIONS" :key="opt.value" :value="opt.value">{{ opt.label }}</option>
            </select>
          </div>
          <button class="text-sm text-red-600 hover:underline" @click="removeLink(index)">Удалить</button>
        </div>
      </div>

      <div class="flex flex-wrap items-center gap-3">
        <button class="btn-primary" @click="addLink">＋ Добавить соцсеть</button>
        <button class="btn-secondary" :disabled="saving" @click="save">
          {{ saving ? 'Сохранение...' : 'Сохранить' }}
        </button>
      </div>
    </div>
  </div>
</template>

<style scoped>
.btn-primary {
  @apply inline-flex items-center gap-1.5 bg-accent px-4 py-2 text-sm font-medium text-white transition hover:bg-accent/90 disabled:opacity-50;
}
.btn-secondary {
  @apply inline-flex items-center gap-1.5 border border-foreground/10 bg-foreground/5 px-4 py-2 text-sm font-medium text-foreground transition hover:bg-foreground/10 disabled:opacity-50;
}
</style>
